updated = 0
not_found = []
for gear in Gear.objects.all():
    if gear.name in descriptions:
        gear.description = descriptions[gear.name]
        gear.save()
        updated += 1
    else:
        not_found.append(gear.name)

print(f'Оновлено описи для {updated} товарів!')
if not_found:
    print(f'\nНе знайдено опис для:')
    for n in not_found:
        print(f'  - {n}')
